// src/pages/LandingPage.js
import React, { useState } from "react";
import { registerUser, loginUser } from "../utils/firebase";
import "./LandingPage.css";

/* ─── password strength ──────────────────────────────────────────────────── */
function getStrength(pw) {
  if (!pw) return { score: 0, label: "", color: "" };
  let score = 0;
  if (pw.length >= 8)            score++;
  if (/[A-Z]/.test(pw))         score++;
  if (/[0-9]/.test(pw))         score++;
  if (/[^A-Za-z0-9]/.test(pw)) score++;
  const map = [
    { label: "",       color: "" },
    { label: "Weak",   color: "#ef4444" },
    { label: "Fair",   color: "#f59e0b" },
    { label: "Good",   color: "#6366f1" },
    { label: "Strong", color: "#22c55e" },
  ];
  return { score, ...map[score] };
}

/* ─── CLARIO logo mark — C with sparkle, matching real logo ─────────────── */
const ClarioLogo = ({ size = 38 }) => (
  <svg width={size} height={size} viewBox="0 0 80 80" fill="none">
    <defs>
      <linearGradient id="cGrad" x1="0" y1="0" x2="80" y2="80" gradientUnits="userSpaceOnUse">
        <stop offset="0%" stopColor="#a78bfa"/>
        <stop offset="100%" stopColor="#7c6cfc"/>
      </linearGradient>
    </defs>
    {/* C arc — thick stroke open on right */}
    <path
      d="M68 20 A34 34 0 1 0 68 60"
      stroke="url(#cGrad)"
      strokeWidth="11"
      strokeLinecap="round"
      fill="none"
    />
    {/* 4-point sparkle inside the C opening */}
    <path
      d="M66 40 L69 34 L72 40 L69 46 Z"
      fill="url(#cGrad)"
      opacity="0.9"
    />
    <path
      d="M63 40 L69 37.5 L75 40 L69 42.5 Z"
      fill="url(#cGrad)"
      opacity="0.9"
    />
  </svg>
);

/* ─── icons ──────────────────────────────────────────────────────────────── */
const EyeIcon = ({ crossed }) => crossed ? (
  <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
    <path d="M1 8s2.5-5 7-5 7 5 7 5-2.5 5-7 5-7-5-7-5z" stroke="#9ca3af" strokeWidth="1.5"/>
    <circle cx="8" cy="8" r="2" stroke="#9ca3af" strokeWidth="1.5"/>
    <path d="M2 2l12 12" stroke="#9ca3af" strokeWidth="1.5" strokeLinecap="round"/>
  </svg>
) : (
  <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
    <path d="M1 8s2.5-5 7-5 7 5 7 5-2.5 5-7 5-7-5-7-5z" stroke="#9ca3af" strokeWidth="1.5"/>
    <circle cx="8" cy="8" r="2" stroke="#9ca3af" strokeWidth="1.5"/>
  </svg>
);

const LockIcon = () => (
  <svg width="15" height="15" viewBox="0 0 15 15" fill="none">
    <rect x="2.5" y="6.5" width="10" height="7" rx="1.5" stroke="#9ca3af" strokeWidth="1.4"/>
    <path d="M4.5 6.5V4.5a3 3 0 016 0v2" stroke="#9ca3af" strokeWidth="1.4" strokeLinecap="round"/>
  </svg>
);
const MailIcon = () => (
  <svg width="15" height="15" viewBox="0 0 15 15" fill="none">
    <rect x="1" y="3" width="13" height="9" rx="1.5" stroke="#9ca3af" strokeWidth="1.4"/>
    <path d="M1 5l6.5 4.5L14 5" stroke="#9ca3af" strokeWidth="1.4" strokeLinecap="round"/>
  </svg>
);
const UserIcon = () => (
  <svg width="15" height="15" viewBox="0 0 15 15" fill="none">
    <circle cx="7.5" cy="5" r="3" stroke="#9ca3af" strokeWidth="1.4"/>
    <path d="M1.5 13.5c0-3.314 2.686-6 6-6s6 2.686 6 6" stroke="#9ca3af" strokeWidth="1.4" strokeLinecap="round"/>
  </svg>
);

/* ─── Register left illustration (waveform + chat bubble) ───────────────── */
const RegisterIllus = () => (
  <svg width="160" height="140" viewBox="0 0 160 140" fill="none">
    <ellipse cx="80" cy="130" rx="60" ry="9" fill="#ddd6fe" opacity="0.4"/>
    <circle cx="80" cy="62" r="50" fill="#f5f3ff" opacity="0.9"/>
    <circle cx="80" cy="62" r="36" fill="#ede9fe"/>
    {/* waveform bars */}
    <rect x="50" y="54" width="6" height="16" rx="3" fill="#a78bfa"/>
    <rect x="61" y="46" width="6" height="32" rx="3" fill="#7c6cfc"/>
    <rect x="72" y="51" width="6" height="22" rx="3" fill="#a78bfa"/>
    <rect x="83" y="40" width="6" height="44" rx="3" fill="#7c6cfc"/>
    <rect x="94" y="49" width="6" height="26" rx="3" fill="#a78bfa"/>
    <rect x="105" y="55" width="6" height="14" rx="3" fill="#7c6cfc"/>
    {/* chat bubble */}
    <rect x="26" y="96" width="50" height="26" rx="13" fill="#c4b5fd"/>
    <circle cx="40" cy="109" r="3" fill="white"/>
    <circle cx="51" cy="109" r="3" fill="white"/>
    <circle cx="62" cy="109" r="3" fill="white"/>
    {/* sparkles */}
    <circle cx="126" cy="30" r="4.5" fill="#c4b5fd" opacity="0.7"/>
    <circle cx="22"  cy="46" r="3"   fill="#ddd6fe" opacity="0.9"/>
    <circle cx="133" cy="76" r="2"   fill="#a78bfa" opacity="0.6"/>
  </svg>
);

/* ─── Login left illustration (microphone) ──────────────────────────────── */
const LoginIllus = () => (
  <svg width="160" height="170" viewBox="0 0 160 170" fill="none">
    <defs>
      <linearGradient id="micG" x1="58" y1="14" x2="102" y2="94" gradientUnits="userSpaceOnUse">
        <stop offset="0%" stopColor="#b8abf8"/>
        <stop offset="100%" stopColor="#7c6cfc"/>
      </linearGradient>
    </defs>
    <ellipse cx="80" cy="158" rx="50" ry="9" fill="#ede9fe" opacity="0.5"/>
    {/* orbit rings */}
    <circle cx="80" cy="72" r="64" stroke="#f0edff" strokeWidth="1.4"/>
    <circle cx="80" cy="72" r="50" stroke="#e4dfff" strokeWidth="1.4"/>
    {/* mic body */}
    <rect x="58" y="14" width="44" height="70" rx="22" fill="url(#micG)"/>
    {/* grille lines */}
    <line x1="66" y1="31" x2="94" y2="31" stroke="white" strokeWidth="1.2" opacity="0.3"/>
    <line x1="66" y1="43" x2="94" y2="43" stroke="white" strokeWidth="1.2" opacity="0.3"/>
    <line x1="66" y1="55" x2="94" y2="55" stroke="white" strokeWidth="1.2" opacity="0.3"/>
    {/* stand */}
    <path d="M80 84 L80 112" stroke="#7c6cfc" strokeWidth="4" strokeLinecap="round"/>
    <path d="M60 112 Q80 119 100 112" stroke="#7c6cfc" strokeWidth="4" strokeLinecap="round"/>
    {/* sound waves */}
    <path d="M40 53 Q32 70 40 87" stroke="#a78bfa" strokeWidth="2.2" fill="none" strokeLinecap="round" opacity="0.8"/>
    <path d="M28 45 Q17 70 28 95" stroke="#c4b5fd" strokeWidth="2"   fill="none" strokeLinecap="round" opacity="0.5"/>
    <path d="M120 53 Q128 70 120 87" stroke="#a78bfa" strokeWidth="2.2" fill="none" strokeLinecap="round" opacity="0.8"/>
    <path d="M132 45 Q143 70 132 95" stroke="#c4b5fd" strokeWidth="2"  fill="none" strokeLinecap="round" opacity="0.5"/>
    {/* sparkles */}
    <circle cx="128" cy="24" r="5"   fill="#c4b5fd"/>
    <circle cx="24"  cy="40" r="3.5" fill="#ddd6fe"/>
    <circle cx="138" cy="60" r="2.5" fill="#a78bfa"/>
  </svg>
);

/* ═══════════════════════════════════════════════════════════════════════════
   PAGE
   ═══════════════════════════════════════════════════════════════════════════ */
export default function LandingPage({ navigate }) {
  const [mode, setMode]         = useState("login");
  const [name, setName]         = useState("");
  const [email, setEmail]       = useState("");
  const [password, setPassword] = useState("");
  const [confirm, setConfirm]   = useState("");
  const [showPw, setShowPw]     = useState(false);
  const [showCf, setShowCf]     = useState(false);
  const [remember, setRemember] = useState(false);
  const [error, setError]       = useState("");
  const [loading, setLoading]   = useState(false);

  const strength = getStrength(password);

  const switchMode = (m) => {
    setMode(m); setError("");
    setName(""); setEmail(""); setPassword(""); setConfirm("");
    setShowPw(false); setShowCf(false);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    if (mode === "register") {
      if (!name.trim())         return setError("Please enter your name.");
      if (password.length < 6)  return setError("Password must be at least 6 characters.");
      if (password !== confirm)  return setError("Passwords do not match.");
    }
    setLoading(true);
    try {
      if (mode === "register") await registerUser(name.trim(), email.trim(), password);
      else                      await loginUser(email.trim(), password);
      navigate("dashboard");
    } catch (err) {
      const msg = err.code || err.message;
      if (msg.includes("email-already-in-use"))   setError("That email is already registered. Try logging in.");
      else if (msg.includes("user-not-found"))    setError("No account found with that email.");
      else if (msg.includes("wrong-password"))    setError("Incorrect password.");
      else if (msg.includes("invalid-email"))     setError("Please enter a valid email address.");
      else if (msg.includes("too-many-requests")) setError("Too many attempts. Please wait a moment.");
      else setError("Something went wrong. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="lp-bg">
      {/* full-page subtle dot pattern */}
      <div className="lp-bg-dots" />

      {/* ── THE CARD BOX (matches PDF exactly) ── */}
      <div className="lp-card">

        {/* ══ LEFT PANEL ══ */}
        <div className="lp-left">
          <div className="lp-left-dots" />

          {/* brand */}
          <div className="lp-brand">
            <div className="lp-logo-wrap">
              <ClarioLogo size={34} />
            </div>
            <div>
              <div className="lp-brand-name">CLARIO</div>
              <div className="lp-brand-sub">AI SPEECH COACH</div>
            </div>
          </div>

          {/* copy */}
          <div className="lp-left-body">
            {mode === "register" ? (
              <>
                <h2 className="lp-left-title">Create your<br/>account</h2>
                <p className="lp-left-sub">Start your journey to<br/>confident communication.</p>
              </>
            ) : (
              <>
                <h2 className="lp-left-title">Welcome back! 👋</h2>
                <p className="lp-left-sub">Log in to continue your journey to<br/>confident communication.</p>
              </>
            )}
          </div>

          {/* illustration */}
          <div className="lp-illus">
            {mode === "register" ? <RegisterIllus /> : <LoginIllus />}
          </div>

          {mode === "login" && (
            <p className="lp-copy">© 2026 CLARIO. All rights reserved.</p>
          )}
        </div>

        {/* ══ RIGHT PANEL ══ */}
        <div className="lp-right">
          <h3 className="lp-form-title">
            {mode === "register" ? "Create your account" : "Log in to your account"}
          </h3>
          <p className="lp-form-sub">
            {mode === "register"
              ? "Fill in your details to get started."
              : "Enter your credentials to access your dashboard."}
          </p>

          <form className="lp-form" onSubmit={handleSubmit}>

            {/* REGISTER: name + email */}
            {mode === "register" && (
              <div className="lp-row">
                <div className="lp-field">
                  <label>Full name</label>
                  <div className="lp-iw">
                    <span className="lp-ico"><UserIcon /></span>
                    <input type="text" placeholder="e.g. Maky Aury Okit"
                      value={name} onChange={e => setName(e.target.value)} required />
                  </div>
                </div>
                <div className="lp-field">
                  <label>Email address</label>
                  <div className="lp-iw">
                    <span className="lp-ico"><MailIcon /></span>
                    <input type="email" placeholder="s.sanchez.rolchvincent@cmu.edu.ph"
                      value={email} onChange={e => setEmail(e.target.value)} required />
                  </div>
                </div>
              </div>
            )}

            {/* LOGIN: email */}
            {mode === "login" && (
              <div className="lp-field">
                <label>Email address</label>
                <div className="lp-iw">
                  <span className="lp-ico"><MailIcon /></span>
                  <input type="email" placeholder="s.sanchez.rolchvincent@cmu.edu.ph"
                    value={email} onChange={e => setEmail(e.target.value)} required />
                </div>
              </div>
            )}

            {/* REGISTER: password + confirm */}
            {mode === "register" ? (
              <div className="lp-row">
                <div className="lp-field">
                  <label>Password</label>
                  <div className="lp-iw">
                    <span className="lp-ico"><LockIcon /></span>
                    <input type={showPw ? "text" : "password"} placeholder="••••••••••••"
                      value={password} onChange={e => setPassword(e.target.value)} required />
                    <button type="button" className="lp-eye" onClick={() => setShowPw(v => !v)}>
                      <EyeIcon crossed={showPw} />
                    </button>
                  </div>
                </div>
                <div className="lp-field">
                  <label>Confirm password</label>
                  <div className="lp-iw">
                    <span className="lp-ico"><LockIcon /></span>
                    <input type={showCf ? "text" : "password"} placeholder="••••••••••••"
                      value={confirm} onChange={e => setConfirm(e.target.value)} required />
                    <button type="button" className="lp-eye" onClick={() => setShowCf(v => !v)}>
                      <EyeIcon crossed={showCf} />
                    </button>
                  </div>
                </div>
              </div>
            ) : (
              /* LOGIN: password */
              <div className="lp-field">
                <label>Password</label>
                <div className="lp-iw">
                  <span className="lp-ico"><LockIcon /></span>
                  <input type={showPw ? "text" : "password"} placeholder="••••••••••••"
                    value={password} onChange={e => setPassword(e.target.value)} required />
                  <button type="button" className="lp-eye" onClick={() => setShowPw(v => !v)}>
                    <EyeIcon crossed={showPw} />
                  </button>
                </div>
              </div>
            )}

            {/* strength bar (register) */}
            {mode === "register" && password && (
              <div className="lp-strength">
                <div className="lp-strength-bars">
                  {[1,2,3,4].map(i => (
                    <div key={i} className="lp-seg"
                      style={{ background: i <= strength.score ? strength.color : "#e5e7eb" }} />
                  ))}
                </div>
                <span className="lp-strength-txt" style={{ color: strength.color }}>
                  Password strength: <strong>{strength.label}</strong>
                </span>
              </div>
            )}

            {/* hint (register) */}
            {mode === "register" && (
              <div className="lp-hint">
                <svg width="14" height="14" viewBox="0 0 14 14" fill="none" style={{flexShrink:0,marginTop:1}}>
                  <circle cx="7" cy="7" r="6" stroke="#7c6cfc" strokeWidth="1.2"/>
                  <path d="M7 6v4M7 4.5v.5" stroke="#7c6cfc" strokeWidth="1.2" strokeLinecap="round"/>
                </svg>
                Use at least 8 characters with a mix of letters, numbers, and symbols.
              </div>
            )}

            {/* remember + forgot (login) */}
            {mode === "login" && (
              <div className="lp-meta">
                <label className="lp-remember">
                  <input type="checkbox" checked={remember} onChange={e => setRemember(e.target.checked)} />
                  Remember me
                </label>
                <button type="button" className="lp-forgot">Forgot password?</button>
              </div>
            )}

            {error && <p className="lp-error">⚠️ {error}</p>}

            <button className="lp-submit" type="submit" disabled={loading}>
              {loading
                ? <><span className="lp-spinner"/> {mode === "register" ? "Creating account…" : "Logging in…"}</>
                : <>{mode === "register" ? "Create Account" : "Log In"} <span className="lp-arr">→</span></>
              }
            </button>
          </form>

          {/* social — login only */}
          {mode === "login" && (
            <>
              <div className="lp-divider"><span>or continue with</span></div>
              <div className="lp-social">
                <button className="lp-social-btn" type="button">
                  <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
                    <path d="M17.64 9.2c0-.637-.057-1.251-.164-1.84H9v3.481h4.844c-.209 1.125-.843 2.078-1.796 2.716v2.259h2.908c1.702-1.567 2.684-3.875 2.684-6.615z" fill="#4285F4"/>
                    <path d="M9 18c2.43 0 4.467-.806 5.956-2.184l-2.909-2.259c-.806.54-1.837.86-3.047.86-2.344 0-4.328-1.584-5.036-3.711H.957v2.332A8.997 8.997 0 009 18z" fill="#34A853"/>
                    <path d="M3.964 10.706A5.41 5.41 0 013.682 9c0-.593.102-1.17.282-1.706V4.962H.957A8.996 8.996 0 000 9c0 1.452.348 2.827.957 4.038l3.007-2.332z" fill="#FBBC05"/>
                    <path d="M9 3.58c1.321 0 2.508.454 3.44 1.345l2.582-2.58C13.463.891 11.426 0 9 0A8.997 8.997 0 00.957 4.962L3.964 7.294C4.672 5.163 6.656 3.58 9 3.58z" fill="#EA4335"/>
                  </svg>
                  Google
                </button>
                <button className="lp-social-btn" type="button">
                  <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
                    <rect x="0"   y="0"   width="8.5" height="8.5" fill="#F25022"/>
                    <rect x="9.5" y="0"   width="8.5" height="8.5" fill="#7FBA00"/>
                    <rect x="0"   y="9.5" width="8.5" height="8.5" fill="#00A4EF"/>
                    <rect x="9.5" y="9.5" width="8.5" height="8.5" fill="#FFB900"/>
                  </svg>
                  Microsoft
                </button>
              </div>
            </>
          )}

          <p className="lp-switch">
            {mode === "login"
              ? <>Don't have an account? <button onClick={() => switchMode("register")}>Register here</button></>
              : <>Already have an account? <button onClick={() => switchMode("login")}>Log in here</button></>
            }
          </p>
        </div>
      </div>
    </div>
  );
}
